item.content:encoded:
/* ===================
あわせて読みたい
複数リンク対応カスタマイズ
====================== */
.emphasize-link {
position: relative;
margin: 36px 0 16px;
padding: 16px 10px;
border: 2px solid #f5f5f5;
background-color: #fffbf5;
}
.emphasize-link p:last-child {
margin-bottom: 0;
}
.emphasize-link::before {
position: absolute;
bottom: 100%;
left: -2px;
padding: 2px 6px;
content: "あわせて読みたい";
background-color: #df5f5f5;
color: #fff;
font-weight: bold;
}

